package com.travelassistant.consultation;import jakarta.persistence.*;import java.time.*;import java.util.UUID;
@Entity @Table(name="conversation_streams")public class ConversationStream{@Id @Column(length=36)private String id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="conversation_id")private Conversation conversation;@OneToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="assistant_message_id")private Message assistantMessage;@Enumerated(EnumType.STRING)@Column(nullable=false,length=16)private StreamStatus status;@Column(name="last_event_sequence",nullable=false)private int lastSequence;@Column(name="expires_at",nullable=false)private Instant expiresAt;@Column(name="created_at",nullable=false,updatable=false)private Instant createdAt;@Column(name="completed_at")private Instant completedAt;protected ConversationStream(){}public ConversationStream(Conversation c,Message m,Instant expiry){conversation=c;assistantMessage=m;expiresAt=expiry;status=StreamStatus.ACTIVE;}@PrePersist void init(){id=UUID.randomUUID().toString();createdAt=Instant.now();}public int nextSequence(){return ++lastSequence;}public void connected(){if(status==StreamStatus.DISCONNECTED)status=StreamStatus.ACTIVE;}public void disconnected(){if(status==StreamStatus.ACTIVE)status=StreamStatus.DISCONNECTED;}public void complete(){if(!terminal()){status=StreamStatus.COMPLETED;completedAt=Instant.now();}}public void fail(StreamStatus s){if(!terminal()){status=s;completedAt=Instant.now();}}public boolean terminal(){return status==StreamStatus.COMPLETED||status==StreamStatus.FAILED||status==StreamStatus.CANCELLED;}public String getId(){return id;}public Conversation getConversation(){return conversation;}public Message getAssistantMessage(){return assistantMessage;}public StreamStatus getStatus(){return status;}public int getLastSequence(){return lastSequence;}public Instant getExpiresAt(){return expiresAt;}}
